local note = Adv.NoteInfoCustom([[※Nhái theo trò chơi <b>Hoshi no Kirby</b> (Kirby Tinh tú) của Nintendo, thường được biết đến qua nhan đề tiếng Anh là <b>Kirby's Dream Land</b>.]],1000)
