Adv.kayamoriTalk([[Uầy, ra là bọn này sao! Lũ "Narby Tinh tú" danh bất hư truyền đây à!]],"VC_MC00_00_09_05_Novel_00000_RKayamori",nil)
Adv.talkWithIcon("YIzumi",[[Người ta có đế thêm chữ "Tinh tú" vào đâu! Láo nháo là bị đánh gậy bản quyền nhé.]],"VC_MC00_00_09_05_Novel_00001_YIzumi")Adv.hide(note, 0.3)
Adv.talkWithIcon("KAsakura",[[Oa, giỏi quá! Nó vừa nhảy lên kìa! Nhìn vậy mà nhanh nhẹn quá chừng!]],"VC_MC00_00_09_05_Novel_00002_KAsakura")
