Adv.talkWithIcon("TTojo",[[Bọn chúng xuất hiện với động cơ gì mới được... Chuyện này nhất định phải điều tra kỹ.]],"VC_MC00_00_09_05_Novel_00004_TTojo")
Adv.talkWithIcon("YIzumi",[[Làm tình báo thì mấy chuyện này phải biết chứ. Người ta trông chờ ở cậu vì lẽ gì nào?]],"VC_MC00_00_09_05_Novel_00005_YIzumi")
Adv.talkWithIcon("KAsakura",[[Sinh vật này rốt cuộc thì có lai lịch như thế nào nhỉ?]],"VC_MC00_00_09_05_Novel_00006_KAsakura")
